+        let mut output = Vec::with_capacity(input.len() * 3 / 4);
+        let mut buffer = 0u32;
+        let mut bits = 0u8;
+
+        for &byte in input {
+            if byte == b'=' {
+                break;
+            }
+            let value = DECODE_TABLE[byte as usize];
+            if value < 0 {
+                continue; // Skip whitespace/invalid
+            }
+            buffer = (buffer << 6) | (value as u32);
+            bits += 6;
+            if bits >= 8 {
+                bits -= 8;
+                output.push((buffer >> bits) as u8);
+                buffer &= (1 << bits) - 1;
+            }
+        }
