+    /// Process bytes while in paste mode.
+    fn process_paste_byte(&mut self, byte: u8) -> Option<Event> {
+        // DoS protection
+        if self.paste_buffer.len() >= MAX_PASTE_LEN {
+            // Silently drop excess content
+            return None;
+        }
