+/// A rectangle for scissor regions and bounds.
+///
+/// Uses terminal coordinates (0-indexed, origin at top-left).
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
+pub struct Rect {
+    /// Left edge (inclusive).
+    pub x: u16,
+    /// Top edge (inclusive).
+    pub y: u16,
+    /// Width in cells.
+    pub width: u16,
+    /// Height in cells.
+    pub height: u16,
+}
