+    #[test]
+    fn stylesheet_thread_safe_reads() {
+        use std::sync::Arc;
+        use std::thread;
+
+        let sheet = Arc::new(StyleSheet::new());
+        sheet.define("test", Style::new().bold());
+
+        let handles: Vec<_> = (0..4)
+            .map(|_| {
+                let sheet = Arc::clone(&sheet);
+                thread::spawn(move || {
+                    for _ in 0..100 {
+                        let _ = sheet.get("test");
+                    }
+                })
+            })
+            .collect();
+
+        for handle in handles {
+            handle.join().unwrap();
+        }
+    }
